from dataclasses import dataclass
from datetime import datetime, UTC
import uuid

@dataclass
class ImplicitSignal:
    id:          str = None
    signal_type: str = ""
    session_id:  str = ""
    turn_index:  int = 0
    value:       float = 0.0   # normalised -1 to +1
    raw:         dict = None
    created_at:  str = None

    def __post_init__(self):
        if self.id is None:
            self.id = str(uuid.uuid4())
        if self.created_at is None:
            self.created_at = datetime.now(UTC).isoformat()
        if self.raw is None:
            self.raw = {}

def make_copy_signal(session_id: str, turn_index: int, copied_chars: int) -> ImplicitSignal:
    # Copy of more chars = stronger positive signal
    strength = min(1.0, copied_chars / 500)
    return ImplicitSignal(
        signal_type="copy",
        session_id=session_id,
        turn_index=turn_index,
        value=strength,
        raw={"copied_chars": copied_chars},
    )

def retry_signal(session_id: str, turn_index: int, retry_count: int) -> ImplicitSignal:
    # Each retry is a negative signal; cap diminishing returns
    value = -min(1.0, retry_count * 0.4)
    return ImplicitSignal(
        signal_type="retry",
        session_id=session_id,
        turn_index=turn_index,
        value=value,
        raw={"retry_count": retry_count},
    )

def abandonment_signal(
    session_id: str,
    turn_index: int,
    seconds_active: float,
    median_session_seconds: float,
) -> ImplicitSignal:
    # Sessions much shorter than median suggest dissatisfaction
    ratio = seconds_active / max(median_session_seconds, 1)
    if ratio >= 0.8:
        value = 0.0   # normal length — no signal
    else:
        value = -(1 - ratio)   # shorter = more negative
    return ImplicitSignal(
        signal_type="abandonment",
        session_id=session_id,
        turn_index=turn_index,
        value=value,
        raw={"seconds_active": seconds_active, "median": median_session_seconds},
    )
